INSERT INTO public.blogs (id, created_at, deleted, updated_at, author, category, content, excerpt, featured, published_date, thumbnail, title, views, display_order) VALUES (19, '2026-04-24 02:10:36.819192', false, '2026-04-24 02:10:36.819192', 'Admin', 'Tin cong nghe', '[{"type":"Heading","body":"AMD Sap Ra Mat RDNA 4"},{"type":"Paragraph","body":"AMD da chinh thuc xac nhan se ra mat dong Radeon RX 8000 series moi vao cuoi nam nay. Day la the he GPU thu 4 cua AMD duoc xay dung tren kien truc RDNA 4 hoan toan moi."},{"type":"Heading","body":"Hieu Nang Du Doan"},{"type":"Paragraph","body":"Theo cac bai ro ri, RX 8000 series se mang lai hieu nang tang 40-60% so voi the he RX 7000 trong khi giu nguyen muc gia hoac tham chi re hon."},{"type":"tip","body":"Neu ban dang dinh mua card do hoa moi, hay cho them vai thang de xem xet chon RX 8000 se mang lai gia tri tot hon."},{"type":"Heading","body":"Thoi Gian Ra Mat Du Kien"},{"type":"Paragraph","body":"AMD du kien se chinh thuc gioi thieu dong RX 8000 tai su kien Computex 2025, voi gia ban du kien tu 8 trieu VND cho mau cap trung."}]', 'Theo thong tin ro ri, dong GPU RDNA 4 cua AMD se tap trung vao phan khuc tam trung, mang lai hieu nang vuot troi voi muc gia hop ly.', true, '2026-04-24 02:10:36.815', '/images/blog/amd-rx8000.jpg', 'Lo Dien Dong Card AMD Radeon RX 8000 Series Sap Ra Mat', 120, 0);
INSERT INTO public.blogs (id, created_at, deleted, updated_at, author, category, content, excerpt, featured, published_date, thumbnail, title, views, display_order) VALUES (20, '2026-04-24 02:10:36.835911', false, '2026-04-24 02:10:36.835911', 'Ky thuat vien', 'Huong dan', '[{"type":"Heading","body":"Dung Cu Can Chuan Bi"},{"type":"Paragraph","body":"Truoc khi ve sinh card do hoa, ban can chuan bi: binh khi nen, co mem, kem tan nhiet, tua vit 4 chau, khan sach."},{"type":"Heading","body":"Cac Buoc Ve Sinh Chi Tiet"},{"type":"steps","items":[{"step":1,"title":"Thao Card khoi may tinh","desc":"Tat nguon, rut het day, dung tua vit mo nap thung va nhe nhang thao card ra."},{"step":2,"title":"Xit khi nen vao canh quat","desc":"Giu canh quat co dinh bang tay, xit khi nen manh de thoi bay bui ban."},{"step":3,"title":"Lap kem tan nhiet moi","desc":"Dung co sach lau sach kem cu, boi kem tan nhiet moi len chip GPU."},{"step":4,"title":"Lap lai va kiem tra","desc":"Lap card tro lai may, bat may va kiem tra nhiet do xem co giam khong."}]},{"type":"tip","body":"Nen ve sinh card do hoa moi 6 thang 1 lan, dac biet neu ban song o moi truong nhieu bui."}]', 'Ve sinh VGA dinh ky giup tang tuoi tho va giam nhiet do hoat dong, duy tri hieu nang on dinh cho card do hoa cua ban.', false, '2026-04-24 02:10:36.835', '/images/blog/vesinh.jpg', 'Huong Dan Ve Sinh Card Do Hoa An Toan Tai Nha', 250, 0);
INSERT INTO public.blogs (id, created_at, deleted, updated_at, author, category, content, excerpt, featured, published_date, thumbnail, title, views, display_order) VALUES (21, '2026-04-24 02:10:36.838443', false, '2026-04-24 02:10:36.838443', 'Gaming Expert', 'Danh gia', '[{"type":"Heading","body":"Tong Quan Hai Doi Thu"},{"type":"Paragraph","body":"RTX 4070 Super co muc gia 16.5 trieu, trong khi RX 7800 XT duoc ban quanh muc 15.9 trieu. Ca hai deu la lua chon chat luong o phan khuc tam cao."},{"type":"Heading","body":"Ket Luan"},{"type":"Paragraph","body":"Neu uu tien DLSS 4 va ray tracing, chon RTX 4070 Super. Neu uu tien do phan giai RAM ve gia tri, chon RX 7800 XT."}]', 'RTX 4070 Super va RX 7800 XT la 2 lua chon hang dau trong tam gia 15-18 trieu. Xem so sanh de biet chon card nao phu hop.', true, '2026-04-24 02:10:36.838', '/images/blog/compare.jpg', 'So Sanh RTX 4070 Super vs RX 7800 XT: Chon Card Nao Cho Game Thu Viet?', 480, 0);


